{
  "premium_report": {
    "report_title": "프리미엄 사주 스토리",
    "version": "1.0",
    "sections": [
      {
        "section_id": "section_1",
        "category": "overall",
        "title": "주인공의 흐름",
        "headline": "말의 흐름을 먼저 다듬고, 사람과의 관계를 서서히 다지면서 성과를 만들어 가는 시간이 필요합니다",
        "summary_lines": [
          "지금은 의사소통의 순서를 먼저 정리하고 주의를 기울여 대화를 시작하는 것이 좋습니다.",
          "일과 관계의 균형을 만들기 위해 작은 목표를 차근차근 쌓아가는 습관이 도움이 됩니다.",
          "일상 속 루틴과 금전 관리의 기본을 다지는 것이 안정적인 흐름을 뒷받침합니다."
        ],
        "core_insight": "현재 흐름은 목표를 세운 뒤 방향을 먼저 확인하고 말의 흐름과 전달 순서를 미리 다듬는 자세에서 시작되며, 중요한 순간일수록 흐름을 유지하려는 의도가 큰 역할을 합니다. 혼자 생각을 많이 하는 편이라 대화의 타이밍과 흐름을 정리하는 노력이 관계를 더 편안하게 이어지게 하고, 작은 선택들을 하나씩 풀어 가는 힘이 불확실성을 줄이며 신뢰를 쌓아 갑니다.",
        "strength": "현재의 흐름은 관계를 다듬고 말의 흐름을 정리하는 과정에서 실제 성과로 이어질 수 있는 뚜렷한 발걸음을 남깁니다.",
        "risk": "한꺼번에 많은 변화를 시도하기보다 흐름에 맞춘 작은 조정이 필요하고, 말과 행동 사이의 간격이 좁아지면 오해가 생길 수 있습니다.",
        "action_points": [
          "대화의 흐름을 먼저 정리하는 습관을 매일 짧은 시간에 연습하세요.",
          "가장 중요한 말은 흐름에 맞춰 전달하는 습관을 들이세요.",
          "일과 관계의 균형을 유지하기 위해 작은 목표를 하나씩 설정하고 차근차근 달성하는 루틴을 만드세요."
        ],
        "action_note": "지금의 흐름은 대화를 다듬고 관계를 다지는 과정에서 실제 성과로 이어질 수 있습니다. 꾸준한 의사소통과 안정된 루틴이 앞으로의 흐름을 더욱 탄탄하게 만들어 줄 것입니다.\n"
      }
    ]
  }
}
